163→        /// <summary>
164→        /// Gets service auth quota data enriched with Service Tree parent group information.
165→        /// </summary>
166→        /// <returns>Enriched service auth quota data.</returns>
167→        [Route("serviceauthquotas/parentinfo")]
168→        [HttpGet]
169→        public async Task<ServiceAuthQuotaParentInfoResponse> GetServiceAuthQuotaParentInfoAsync()
170→        {
171→            await this.CheckReadPermissionAsync();
172→            var userAlias = PermissionHelper.GetUserAlias(this.User);
173→            var collectedAtUtc = DateTime.UtcNow;
174→
175→            var serviceAuthQuotas = await this.configSvc.GetServiceQuotaAndAuthManagementAsync(userAlias).ConfigureAwait(false);
176→            var cancellationToken = this.HttpContext?.RequestAborted ?? CancellationToken.None;
177→            var parentLookup = await this.parentResolver
178→                .ResolveParentsAsync(serviceAuthQuotas.Select(q => q.ServiceTreeId ?? string.Empty), cancellationToken)
179→                .ConfigureAwait(false);
180→
181→            var items = serviceAuthQuotas.Select(entry =>
182→            {
183→                ParentServiceGroupInfo? parent = parentLookup.TryGetValue(entry.ServiceTreeId ?? string.Empty, out var resolvedParent)
184→                    ? resolvedParent
185→                    : null;
186→                return new ServiceAuthQuotaParentInfo
187→                {
188→                    QuotaAppId = entry.QuotaAppId ?? string.Empty,
189→                    ServiceTreeId = entry.ServiceTreeId ?? string.Empty,
190→                    ServiceName = entry.ServiceName ?? string.Empty,
191→                    ParentServiceGroupId = parent?.ServiceGroupId ?? string.Empty,
192→                    ParentServiceGroupName = parent?.ServiceGroupName ?? string.Empty,
193→                    ParentProduct = parent?.Product ?? string.Empty,
194→                };
195→            }).ToList();
196→
197→            return new ServiceAuthQuotaParentInfoResponse
198→            {
199→                CollectedAtUtc = collectedAtUtc,
200→                Items = items,
201→            };
202→        }
