241→        {
242→            await this.CheckReadPermissionAsync();
243→            if (filter != null && filter.Owner == "@me")
244→            {
245→                filter.Owner = AuthUtil.NormalizeAlias(this.User.GetLoginHint());
246→            }
247→
248→            ////TODO: remove temporary select added for hiding deployed status to avoid confusion
249→            return (await this.configSvc.GetPullRequestsAsync(filter)).Select(s =>
250→            {
251→                if (s.Status == PullRequestStatus.Deployed)
252→                {
253→                    s.Status = PullRequestStatus.Completed;
254→                }
255→
256→                return s;
257→            });
