  5→namespace CodeXCore.ServiceTree
  6→{
  7→    using System;
  8→    using System.Net.Http;
  9→    using System.Net.Http.Headers;
 10→    using System.Security;
 11→    using System.Security.Cryptography;
 12→    using System.Security.Cryptography.X509Certificates;
 13→    using System.Text.Json;
 14→    using System.Threading;
 15→    using System.Threading.Tasks;
 16→    using global::Azure.Core;
 17→    using global::Azure.Identity;
 18→    using Microsoft.Extensions.Logging;
 19→
 20→#pragma warning disable CA1303 // Log messages are not localized.
 21→
 22→    /// <summary>
 23→    /// Lightweight Service Tree client that retrieves node details via REST.
 24→    /// </summary>
 25→    public sealed class ServiceTreeClient : IServiceTreeClient, IDisposable
 26→    {
 27→        private readonly HttpClient httpClient;
 28→        private readonly Uri baseUri;
 29→        private readonly ILogger<ServiceTreeClient> logger;
 30→        private readonly bool isConfigured;
 31→        private readonly ServiceTreeAuthenticationMode authenticationMode;
 32→        private readonly TokenCredential? tokenCredential;
 33→        private readonly string? tokenScope;
 34→
 35→        /// <summary>
 36→        /// Initializes a new instance of the <see cref="ServiceTreeClient"/> class.
 37→        /// </summary>
 38→        /// <param name="options">Client options.</param>
 39→        /// <param name="logger">Logger instance.</param>
 40→        public ServiceTreeClient(ServiceTreeClientOptions options, ILogger<ServiceTreeClient> logger)
 41→        {
 42→            if (options == null)
 43→            {
 44→                throw new ArgumentNullException(nameof(options));
 45→            }
 46→
 47→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 48→            this.baseUri = new Uri(this.AppendTrailingSlash(options.Endpoint));
 49→            this.authenticationMode = options.AuthenticationMode;
 50→
 51→#pragma warning disable CA2000 // HttpClient owns handler when disposeHandler is true.
 52→            HttpClientHandler handler = new HttpClientHandler();
 53→#pragma warning restore CA2000
 54→            try
 55→            {
 56→                if (this.authenticationMode == ServiceTreeAuthenticationMode.Aad)
 57→                {
 58→                    this.tokenCredential = this.TryCreateAadCredential(options, out var scope);
 59→                    if (this.tokenCredential != null && !string.IsNullOrWhiteSpace(scope))
 60→                    {
 61→                        this.tokenScope = scope;
 62→                        this.isConfigured = true;
 63→                    }
 64→                    else
 65→                    {
 66→                        this.logger.LogWarning("ServiceTreeClient: AAD authentication is enabled, but credentials are not configured.");
 67→                        this.isConfigured = false;
 68→                    }
 69→                }
 70→                else if (this.authenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
 71→                {
 72→                    this.tokenCredential = this.CreateDefaultAzureCredential(options, out var scope);
 73→                    if (this.tokenCredential != null && !string.IsNullOrWhiteSpace(scope))
 74→                    {
 75→                        this.tokenScope = scope;
 76→                        this.isConfigured = true;
 77→                    }
 78→                    else
 79→                    {
 80→                        this.logger.LogWarning("ServiceTreeClient: DefaultAzureCredential auth is enabled, but no token scope is configured.");
 81→                        this.isConfigured = false;
 82→                    }
 83→                }
 84→                else
 85→                {
 86→                    var cert = this.TryLoadCertificate(options);
 87→                    if (cert != null)
 88→                    {
 89→                        handler.ClientCertificates.Add(cert);
 90→                        this.isConfigured = true;
 91→                    }
 92→                    else
 93→                    {
 94→                        this.logger.LogWarning("ServiceTreeClient: no client certificate found. Requests may fail without cert-based auth.");
 95→                        this.isConfigured = false;
 96→                    }
 97→                }
 98→
 99→                this.httpClient = new HttpClient(handler, disposeHandler: true);
100→                handler = null;
101→                this.httpClient.Timeout = TimeSpan.FromSeconds(30);
102→            }
103→            finally
104→            {
105→                handler?.Dispose();
106→            }
107→        }
108→
109→        /// <inheritdoc/>
110→        public async Task<ServiceTreeNode?> GetServiceHierarchyAsync(Guid id, CancellationToken cancellationToken)
111→        {
112→            if (!this.isConfigured)
113→            {
114→                return null;
115→            }
116→
117→            var requestUri = new Uri(this.baseUri, $"ServiceHierarchy({id})?$select=Id,Name,OrganizationPath,Path,NodeType,ParentNodeType");
118→            try
119→            {
120→                using var request = new HttpRequestMessage(HttpMethod.Get, requestUri);
121→                if (this.authenticationMode == ServiceTreeAuthenticationMode.Aad
122→                    || this.authenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
123→                {
124→                    var token = await this.GetAccessTokenAsync(cancellationToken).ConfigureAwait(false);
125→                    if (string.IsNullOrWhiteSpace(token))
126→                    {
127→                        return null;
128→                    }
129→
130→                    request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
131→                }
132→
133→                using var response = await this.httpClient.SendAsync(request, cancellationToken).ConfigureAwait(false);
134→                if (!response.IsSuccessStatusCode)
135→                {
136→                    var body = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
137→                    this.logger.LogWarning("ServiceTreeClient: request failed ({Status}) for {Id}. Body: {Body}", response.StatusCode, id, body);
138→                    return null;
139→                }
140→
141→                var content = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
142→                if (string.IsNullOrWhiteSpace(content))
143→                {
144→                    return null;
145→                }
146→
147→                using var doc = JsonDocument.Parse(content);
148→                var root = doc.RootElement;
149→
150→                if (root.ValueKind != JsonValueKind.Object)
151→                {
152→                    return null;
153→                }
154→
155→                return new ServiceTreeNode
156→                {
157→                    InternalId = 0,
158→                    Id = this.TryGetString(root, "Id"),
159→                    Level = string.Empty,
160→                    ParentInternalId = 0,
161→                    Name = this.TryGetString(root, "Name"),
162→                    OrganizationPath = this.TryGetString(root, "OrganizationPath"),
163→                    Path = this.TryGetString(root, "Path"),
164→                    NodeType = this.TryGetString(root, "NodeType"),
165→                    ParentNodeType = this.TryGetString(root, "ParentNodeType"),
166→                };
167→            }
168→            catch (OperationCanceledException)
169→            {
170→                throw;
171→            }
172→            catch (CredentialUnavailableException ex)
173→            {
174→                this.logger.LogWarning(ex, "ServiceTreeClient: AAD credentials unavailable for {Id}.", id);
175→                return null;
176→            }
177→            catch (AuthenticationFailedException ex)
178→            {
179→                this.logger.LogWarning(ex, "ServiceTreeClient: AAD authentication failed for {Id}.", id);
180→                return null;
181→            }
182→            catch (HttpRequestException ex)
183→            {
184→                this.logger.LogWarning(ex, "ServiceTreeClient: request failed for {Id}.", id);
185→                return null;
186→            }
187→            catch (JsonException ex)
188→            {
189→                this.logger.LogWarning(ex, "ServiceTreeClient: invalid response for {Id}.", id);
190→                return null;
191→            }
192→            catch (InvalidOperationException ex)
193→            {
194→                this.logger.LogWarning(ex, "ServiceTreeClient: failed to process response for {Id}.", id);
195→                return null;
196→            }
197→            catch (FormatException ex)
198→            {
199→                this.logger.LogWarning(ex, "ServiceTreeClient: malformed response for {Id}.", id);
200→                return null;
201→            }
202→        }
203→
204→        /// <summary>
205→        /// Disposes managed resources.
206→        /// </summary>
207→        public void Dispose()
208→        {
209→            this.httpClient.Dispose();
210→        }
211→
212→        private string AppendTrailingSlash(string endpoint)
213→        {
214→            if (string.IsNullOrWhiteSpace(endpoint))
215→            {
216→                return string.Empty;
217→            }
218→
219→            return endpoint.EndsWith("/", StringComparison.Ordinal) ? endpoint : $"{endpoint}/";
220→        }
221→
222→        private async Task<string> GetAccessTokenAsync(CancellationToken cancellationToken)
223→        {
224→            if (this.tokenCredential == null || string.IsNullOrWhiteSpace(this.tokenScope))
225→            {
226→                return string.Empty;
227→            }
228→
229→            var tokenRequest = new TokenRequestContext(new[] { this.tokenScope });
230→            var token = await this.tokenCredential.GetTokenAsync(tokenRequest, cancellationToken).ConfigureAwait(false);
231→            return token.Token;
232→        }
233→
234→        private TokenCredential? TryCreateAadCredential(ServiceTreeClientOptions options, out string scope)
235→        {
236→            scope = this.ResolveAadScope(options);
237→            if (string.IsNullOrWhiteSpace(scope))
238→            {
239→                this.logger.LogWarning("ServiceTreeClient: AAD scope is not configured.");
240→                return null;
241→            }
242→
243→            if (!string.IsNullOrWhiteSpace(options.AadClientSecret))
244→            {
245→                if (string.IsNullOrWhiteSpace(options.AadTenantId) || string.IsNullOrWhiteSpace(options.AadClientId))
246→                {
247→                    this.logger.LogWarning("ServiceTreeClient: AAD client secret set but tenant/client id missing.");
248→                    return null;
249→                }
250→
251→                return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
252→            }
253→
254→            if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64))
255→            {
256→                if (string.IsNullOrWhiteSpace(options.AadTenantId) || string.IsNullOrWhiteSpace(options.AadClientId))
257→                {
258→                    this.logger.LogWarning("ServiceTreeClient: AAD client certificate set but tenant/client id missing.");
259→                    return null;
260→                }
261→
262→#pragma warning disable CA2000 // Certificate lifetime is tied to the client.
263→                var certificate = this.TryLoadAadCertificate(options);
264→#pragma warning restore CA2000
265→                if (certificate == null)
266→                {
267→                    return null;
268→                }
269→
270→                var credentialOptions = new ClientCertificateCredentialOptions
271→                {
272→                    SendCertificateChain = true,
273→                };
274→
275→                return new ClientCertificateCredential(options.AadTenantId, options.AadClientId, certificate, credentialOptions);
276→            }
277→
278→            if (!string.IsNullOrWhiteSpace(options.AadClientId))
279→            {
280→                return new ManagedIdentityCredential(options.AadClientId);
281→            }
282→
283→            return new ManagedIdentityCredential();
284→        }
285→
286→        private TokenCredential? CreateDefaultAzureCredential(ServiceTreeClientOptions options, out string scope)
287→        {
288→            scope = this.ResolveAadScope(options);
289→            if (string.IsNullOrWhiteSpace(scope))
290→            {
291→                return null;
292→            }
293→
294→            var credentialOptions = new DefaultAzureCredentialOptions
295→            {
296→                ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
297→            };
298→
299→            return new DefaultAzureCredential(credentialOptions);
300→        }
301→
302→        private string ResolveAadScope(ServiceTreeClientOptions options)
303→        {
304→            if (!string.IsNullOrWhiteSpace(options.AadScope))
305→            {
306→                return options.AadScope;
307→            }
308→
309→            if (string.IsNullOrWhiteSpace(options.AadAudience))
310→            {
311→                return string.Empty;
312→            }
313→
314→            var trimmed = options.AadAudience.TrimEnd('/');
315→            return $"{trimmed}/.default";
316→        }
317→
318→        private string TryGetString(JsonElement element, string propertyName)
319→        {
320→            if (element.TryGetProperty(propertyName, out var value) && value.ValueKind == JsonValueKind.String)
321→            {
322→                return value.GetString() ?? string.Empty;
323→            }
324→
325→            return string.Empty;
326→        }
327→
328→        private X509Certificate2? TryLoadCertificate(ServiceTreeClientOptions options)
329→        {
330→            if (!string.IsNullOrWhiteSpace(options.CertificateBase64))
331→            {
332→                try
333→                {
334→                    var raw = Convert.FromBase64String(options.CertificateBase64);
335→                    return new X509Certificate2(raw, options.CertificatePassword, X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet);
336→                }
337→                catch (FormatException ex)
338→                {
339→                    this.logger.LogWarning(ex, "ServiceTreeClient: failed to load certificate from base64.");
340→                }
341→                catch (CryptographicException ex)
342→                {
343→                    this.logger.LogWarning(ex, "ServiceTreeClient: failed to load certificate from base64.");
344→                }
345→            }
346→
347→            if (string.IsNullOrWhiteSpace(options.CertificateThumbprint))
348→            {
349→                return null;
350→            }
351→
352→            try
353→            {
354→                using var store = new X509Store(options.CertificateStoreName, options.CertificateStoreLocation);
355→                store.Open(OpenFlags.ReadOnly);
356→                var found = store.Certificates.Find(X509FindType.FindByThumbprint, options.CertificateThumbprint, validOnly: false);
357→                return found.Count > 0 ? found[0] : null;
358→            }
359→            catch (CryptographicException ex)
360→            {
361→                this.logger.LogWarning(ex, "ServiceTreeClient: failed to load certificate from store.");
362→                return null;
363→            }
364→            catch (SecurityException ex)
365→            {
366→                this.logger.LogWarning(ex, "ServiceTreeClient: failed to load certificate from store.");
367→                return null;
368→            }
369→        }
370→
371→        private X509Certificate2? TryLoadAadCertificate(ServiceTreeClientOptions options)
372→        {
373→            try
374→            {
375→                var raw = Convert.FromBase64String(options.AadClientCertificateBase64);
376→                return new X509Certificate2(raw, options.AadClientCertificatePassword, X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet);
377→            }
378→            catch (FormatException ex)
379→            {
380→                this.logger.LogWarning(ex, "ServiceTreeClient: failed to load AAD certificate from base64.");
381→            }
382→            catch (CryptographicException ex)
383→            {
384→                this.logger.LogWarning(ex, "ServiceTreeClient: failed to load AAD certificate from base64.");
385→            }
386→
387→            return null;
388→        }
389→    }
390→
391→#pragma warning restore CA1303
392→}
