  5→namespace CodeXCore.ServiceTree
  6→{
  7→    using System;
  8→    using System.Collections.Concurrent;
  9→    using System.Collections.Generic;
 10→    using System.Linq;
 11→    using System.Text;
 12→    using System.Threading;
 13→    using System.Threading.Tasks;
 14→    using Microsoft.Extensions.Logging;
 15→
 16→    /// <summary>
 17→    /// Resolves Service Tree node parent group info using the flattened hierarchy table and a hardcoded catalog.
 18→    /// </summary>
 19→    public sealed class ServiceTreeParentResolver : IServiceTreeParentResolver
 20→    {
 21→        private static readonly ParentServiceGroupInfo UnknownParent = new ParentServiceGroupInfo(string.Empty, string.Empty, string.Empty);
 22→
 23→        private readonly IServiceTreeNodeLookup nodeLookup;
 24→        private readonly ILogger<ServiceTreeParentResolver> logger;
 25→        private readonly ConcurrentDictionary<string, ParentServiceGroupInfo> cache =
 26→            new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 27→
 28→        /// <summary>
 29→        /// Initializes a new instance of the <see cref="ServiceTreeParentResolver"/> class.
 30→        /// </summary>
 31→        /// <param name="nodeLookup">Service Tree node lookup.</param>
 32→        /// <param name="logger">Logger instance.</param>
 33→        public ServiceTreeParentResolver(IServiceTreeNodeLookup nodeLookup, ILogger<ServiceTreeParentResolver> logger)
 34→        {
 35→            this.nodeLookup = nodeLookup ?? throw new ArgumentNullException(nameof(nodeLookup));
 36→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 37→        }
 38→
 39→        /// <inheritdoc/>
 40→        public async Task<IReadOnlyDictionary<string, ParentServiceGroupInfo>> ResolveParentsAsync(
 41→            IEnumerable<string> serviceTreeIds,
 42→            CancellationToken cancellationToken)
 43→        {
 44→            var results = new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 45→            var uniqueIds = (serviceTreeIds ?? Enumerable.Empty<string>())
 46→                .Where(id => !string.IsNullOrWhiteSpace(id))
 47→                .Select(id => id.Trim())
 48→                .Distinct(StringComparer.OrdinalIgnoreCase)
 49→                .ToList();
 50→
 51→            if (uniqueIds.Count == 0)
 52→            {
 53→                return results;
 54→            }
 55→
 56→            var idsToQuery = new List<string>();
 57→
 58→            foreach (var id in uniqueIds)
 59→            {
 60→                if (this.cache.TryGetValue(id, out var cached))
 61→                {
 62→                    results[id] = cached;
 63→                    continue;
 64→                }
 65→
 66→                if (ServiceTreeParentGroupCatalog.ParentsById.TryGetValue(id, out var directMatch))
 67→                {
 68→                    this.cache[id] = directMatch;
 69→                    results[id] = directMatch;
 70→                    continue;
 71→                }
 72→
 73→                idsToQuery.Add(id);
 74→            }
 75→
 76→            if (idsToQuery.Count > 0)
 77→            {
 78→                // Use the flattened hierarchy table — one query, no traversal needed.
 79→                var hierarchyResults = await this.nodeLookup
 80→                    .GetHierarchyNodesByServiceIdsAsync(idsToQuery, cancellationToken)
 81→                    .ConfigureAwait(false);
 82→
 83→                this.logger.LogInformation(
 84→                    "ServiceTreeParentResolver: Queried {QueryCount} IDs, got {ResultCount} hierarchy results.",
 85→                    idsToQuery.Count,
 86→                    hierarchyResults.Count);
 87→
 88→                foreach (var id in idsToQuery)
 89→                {
 90→                    if (hierarchyResults.TryGetValue(id, out var hierarchyNode))
 91→                    {
 92→                        var parent = this.MatchFromHierarchyNode(hierarchyNode);
 93→                        if (parent != null)
 94→                        {
 95→                            this.logger.LogInformation(
 96→                                "ServiceTreeParentResolver: Resolved {Id} → ServiceGroupId={ServiceGroupId}, ServiceGroupName={ServiceGroupName}, Product={Product}.",
 97→                                id,
 98→                                parent.ServiceGroupId,
 99→                                parent.ServiceGroupName,
100→                                parent.Product);
101→                            this.cache[id] = parent;
102→                            results[id] = parent;
103→                            continue;
104→                        }
105→
106→                        this.logger.LogWarning(
107→                            "ServiceTreeParentResolver: Hierarchy returned node for {Id} but no ServiceGroupId found.",
108→                            id);
109→                    }
110→                    else
111→                    {
112→                        this.logger.LogWarning(
113→                            "ServiceTreeParentResolver: No hierarchy result for {Id}.",
114→                            id);
115→                    }
116→
117→                    // Not found in hierarchy or no ServiceGroupId — mark as unknown.
118→                    this.cache[id] = UnknownParent;
119→                    results[id] = UnknownParent;
120→                }
121→            }
122→
123→            return results;
124→        }
125→
126→        private ParentServiceGroupInfo? MatchFromHierarchyNode(ServiceTreeNode node)
127→        {
128→            // Check each ancestor level by ID first, then by name.
129→            // Order: ServiceGroup → Organization → Division (most specific to least).
130→            string[] ancestorIds = new[]
131→            {
132→                node.ServiceGroupId,
133→                node.OrganizationId,
134→                node.DivisionId,
135→            };
136→
137→            foreach (var ancestorId in ancestorIds)
138→            {
139→                if (!string.IsNullOrWhiteSpace(ancestorId)
140→                    && ServiceTreeParentGroupCatalog.ParentsById.TryGetValue(ancestorId, out var match))
141→                {
142→                    return match;
143→                }
144→            }
145→
146→            string[] ancestorNames = new[]
147→            {
148→                node.ServiceGroupName,
149→                node.OrganizationName,
150→                node.DivisionName,
151→            };
152→
153→            foreach (var name in ancestorNames)
154→            {
155→                var nameMatch = this.MatchParentByName(name);
156→                if (nameMatch != null)
157→                {
158→                    return nameMatch;
159→                }
160→            }
161→
162→            // No catalog match — but if the hierarchy provides a ServiceGroupId,
163→            // return it directly with empty Product.
164→            if (!string.IsNullOrWhiteSpace(node.ServiceGroupId))
165→            {
166→                return new ParentServiceGroupInfo(
167→                    node.ServiceGroupId,
168→                    node.ServiceGroupName ?? string.Empty,
169→                    string.Empty);
170→            }
171→
172→            return null;
173→        }
174→
175→        private ParentServiceGroupInfo? MatchParentByName(string name)
176→        {
177→            if (string.IsNullOrWhiteSpace(name))
178→            {
179→                return null;
180→            }
181→
182→            var normalizedName = this.NormalizeName(name);
183→            foreach (var parent in ServiceTreeParentGroupCatalog.ParentsByNameDescending)
184→            {
185→                if (this.NormalizeName(parent.ServiceGroupName) == normalizedName)
186→                {
187→                    return parent;
188→                }
189→            }
190→
191→            return null;
192→        }
193→
194→        private string NormalizeName(string input)
195→        {
196→            if (string.IsNullOrWhiteSpace(input))
197→            {
198→                return string.Empty;
199→            }
200→
201→            var normalized = input.Replace("&", "and", StringComparison.OrdinalIgnoreCase);
202→            var builder = new StringBuilder(normalized.Length);
203→            foreach (var ch in normalized)
204→            {
205→                if (char.IsLetterOrDigit(ch))
206→                {
207→                    builder.Append(char.ToLowerInvariant(ch));
208→                }
209→                else if (char.IsWhiteSpace(ch))
210→                {
211→                    builder.Append(' ');
212→                }
213→            }
214→
215→            return string.Join(' ', builder.ToString().Split(' ', StringSplitOptions.RemoveEmptyEntries));
216→        }
217→    }
218→}
