226→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryBatchByIdsAsync(
227→            IReadOnlyList<string> batch,
228→            CancellationToken cancellationToken)
229→        {
230→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
231→            if (batch.Count == 0)
232→            {
233→                return results;
234→            }
235→
236→            var query = this.BuildQueryByIds(batch);
237→            var requestProperties = new ClientRequestProperties();
238→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeKusto.{Guid.NewGuid():N}";
239→
240→            try
241→            {
242→                using var provider = this.CreateQueryProvider();
243→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
244→
245→                // Kusto V2 responses may return metadata frames before the data.
246→                // Advance past result sets that have no rows.
247→                do
248→                {
249→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
250→                    if (idOrdinal < 0)
251→                    {
252→                        continue;
253→                    }
254→
255→                    var internalIdOrdinal = this.TryGetOrdinal(reader, "InternalId");
256→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
257→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
258→                    var organizationOrdinal = this.TryGetOrdinal(reader, "Organization");
259→                    var parentOrganizationOrdinal = this.TryGetOrdinal(reader, "ParentOrganizationId");
260→
261→                    while (reader.Read())
262→                    {
263→                        var id = this.ReadString(reader, idOrdinal);
264→                        if (string.IsNullOrWhiteSpace(id))
265→                        {
266→                            continue;
267→                        }
268→
269→                        results[id] = new ServiceTreeNode
270→                        {
271→                            InternalId = this.ReadInt(reader, internalIdOrdinal),
272→                            Id = id,
273→                            Level = this.ReadString(reader, levelOrdinal),
274→                            Name = this.ReadString(reader, nameOrdinal),
275→                            OrganizationPath = this.ReadString(reader, organizationOrdinal),
276→                            Path = string.Empty,
277→                            ParentInternalId = this.ReadInt(reader, parentOrganizationOrdinal),
278→                            ParentId = this.ReadString(reader, parentOrganizationOrdinal),
279→                        };
280→                    }
281→                }
282→                while (results.Count == 0 && reader.NextResult());
283→            }
284→            catch (OperationCanceledException)
285→            {
286→                throw;
287→            }
288→            catch (Exception ex)
289→            {
290→                this.logger.LogWarning(ex, "ServiceTreeKustoClient: query failed.");
291→            }
292→
293→            return results;
294→        }
