366→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
367→            IReadOnlyList<string> batch,
368→            CancellationToken cancellationToken)
369→        {
370→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
371→            if (batch.Count == 0)
372→            {
373→                return results;
374→            }
375→
376→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
377→            // cross-key results by whichever hierarchy column matched each row.
378→            var batchSet = new HashSet<string>(
379→                batch.Select(id => id.ToLowerInvariant()),
380→                StringComparer.OrdinalIgnoreCase);
381→
382→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
383→            var builder = new StringBuilder();
384→            builder.AppendLine("let ids = datatable(TargetId:string)[");
385→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
386→            builder.AppendLine("];");
387→            builder.AppendLine($"{hierarchyTable}");
388→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
389→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
390→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
391→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
392→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
393→            builder.AppendLine("| project");
394→            builder.AppendLine("    Id = tostring(ServiceId),");
395→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
396→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
397→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
398→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
399→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
400→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
401→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
402→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
403→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
404→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
405→            var query = builder.ToString();
406→
407→            var requestProperties = new ClientRequestProperties();
408→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
409→
410→            try
411→            {
412→                this.logger.LogInformation(
413→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
414→                    batch.Count,
415→                    this.kustoOptions.ClusterUri,
416→                    this.kustoOptions.Database,
417→                    this.kustoOptions.HierarchyTableName);
418→
419→                using var provider = this.CreateQueryProvider();
420→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
421→
422→                do
423→                {
424→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
425→                    if (idOrdinal < 0)
426→                    {
427→                        continue;
428→                    }
429→
430→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
431→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
432→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
433→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
434→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
435→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
436→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
437→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
438→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
439→
440→                    while (reader.Read())
441→                    {
442→                        var id = this.ReadString(reader, idOrdinal);
443→                        if (string.IsNullOrWhiteSpace(id))
444→                        {
445→                            continue;
446→                        }
447→
448→                        var node = new ServiceTreeNode
449→                        {
450→                            Id = id,
451→                            Name = this.ReadString(reader, nameOrdinal),
452→                            Level = this.ReadString(reader, levelOrdinal),
453→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
454→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
455→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
456→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
457→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
458→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
459→                        };
460→
461→                        // Always key by the native ServiceId for backward compatibility.
462→                        results[id] = node;
463→
464→                        // Also key by any hierarchy ancestor ID that the caller asked for.
465→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
466→                        // find the result via hierarchyResults.TryGetValue(inputId).
467→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
468→                        foreach (var hierarchyId in new[]
469→                        {
470→                            teamGroupId,
471→                            node.ServiceGroupId,
472→                            node.OrganizationId,
473→                            node.DivisionId,
474→                        })
475→                        {
476→                            if (!string.IsNullOrWhiteSpace(hierarchyId)
477→                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
478→                            {
479→                                results[hierarchyId] = node;
480→                            }
481→                        }
482→                    }
483→                }
484→                while (results.Count == 0 && reader.NextResult());
485→
486→                this.logger.LogInformation(
487→                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
488→                    results.Count,
489→                    batch.Count);
490→            }
491→            catch (OperationCanceledException)
492→            {
493→                throw;
494→            }
495→            catch (Exception ex)
496→            {
497→                this.logger.LogWarning(ex, "ServiceTreeKustoClient: hierarchy query failed.");
498→            }
499→
500→            return results;
501→        }
