510→        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
511→        {
512→            for (int i = 0; i < ids.Count; i += batchSize)
513→            {
514→                var count = Math.Min(batchSize, ids.Count - i);
515→                var batch = new List<string>(count);
516→                for (int j = 0; j < count; j++)
517→                {
518→                    batch.Add(ids[i + j]);
519→                }
520→
521→                yield return batch;
522→            }
523→        }
