694→        private string NormalizeIdentifier(string value)
695→        {
696→            if (string.IsNullOrWhiteSpace(value))
697→            {
698→                return value;
699→            }
700→
701→            var trimmed = value.Trim();
702→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
703→                ? trimmed
704→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
705→        }
