12→    /// <summary>
13→    /// Intercepts database connections to provide Azure Active Directory authentication.
14→    /// </summary>
15→    public class AADAuthDBInterceptor : DbConnectionInterceptor
16→    {
17→        /// <summary>
18→        /// The scopes required for the token.
19→        /// </summary>
20→        private static readonly string[] Scopes = new[] { "https://database.windows.net/.default" };
21→
22→        /// <summary>
23→        /// The token credential used for authentication.
24→        /// </summary>
25→        private readonly TokenCredential credentials;
26→
27→        /// <summary>
28→        /// Initializes a new instance of the <see cref="AADAuthDBInterceptor"/> class.
29→        /// </summary>
30→        /// <param name="credentials">The token credential used for authentication.</param>
31→        public AADAuthDBInterceptor(TokenCredential credentials)
32→        {
33→            this.credentials = credentials;
34→        }
35→
36→        /// <summary>
37→        /// Called when a connection is opening.
38→        /// </summary>
39→        /// <param name="connection">The database connection.</param>
40→        /// <param name="eventData">The event data.</param>
41→        /// <param name="result">The interception result.</param>
42→        /// <returns>The same interception result.</returns>
43→        public override InterceptionResult ConnectionOpening(
44→            DbConnection connection,
45→            ConnectionEventData eventData,
46→            InterceptionResult result)
47→        {
48→            var sqlConnection = (SqlConnection)connection;
49→            sqlConnection.AccessToken = this.credentials.GetToken(new TokenRequestContext(Scopes), CancellationToken.None).Token;
50→            return result;
51→        }
52→
53→        /// <summary>
54→        /// Called asynchronously when a connection is opening.
55→        /// </summary>
56→        /// <param name="connection">The database connection.</param>
57→        /// <param name="eventData">The event data.</param>
58→        /// <param name="result">The interception result.</param>
59→        /// <param name="cancellationToken">The cancellation token.</param>
60→        /// <returns>A task that represents the asynchronous operation. The task result contains the interception result.</returns>
61→        public override async ValueTask<InterceptionResult> ConnectionOpeningAsync(
62→            DbConnection connection,
63→            ConnectionEventData eventData,
64→            InterceptionResult result,
65→            CancellationToken cancellationToken = default)
66→        {
67→            var sqlConnection = (SqlConnection)connection;
68→            var token = await this.credentials.GetTokenAsync(new TokenRequestContext(Scopes), CancellationToken.None).ConfigureAwait(false);
69→            sqlConnection.AccessToken = token.Token;
70→            return result;
71→        }
72→    }
73→}
