  7→namespace CodeXCore.Identity
  8→{
  9→    using System;
 10→    using System.Collections.Concurrent;
 11→    using System.Collections.Generic;
 12→    using System.Linq;
 13→    using System.Threading.Tasks;
 14→    using Shared.Core.GraphicAPI;
 15→
 16→    /// <summary>
 17→    /// Manages identity-related operations.
 18→    /// </summary>
 19→    public class IdentityManager
 20→    {
 21→        /// <summary>
 22→        /// The Admins SGO ID.
 23→        /// </summary>
 24→        /// https://ms.portal.azure.com/#view/Microsoft_AAD_IAM/GroupDetailsMenuBlade/~/Overview/groupId/efc73f63-0069-40d7-8ddd-200ce79d77d9/menuId/
 25→        private const string AdminsSGOId = "efc73f63-0069-40d7-8ddd-200ce79d77d9";
 26→
 27→        /// <summary>
 28→        /// The Users SGO ID.
 29→        /// </summary>
 30→        /// https://ms.portal.azure.com/#view/Microsoft_AAD_IAM/GroupDetailsMenuBlade/~/Overview/groupId/87db173b-7703-4aa1-93b1-b5425accf9fc/menuId/
 31→        private const string UsersSGOid = "87db173b-7703-4aa1-93b1-b5425accf9fc";
 32→
 33→        /// <summary>
 34→        /// The expiration time in seconds.
 35→        /// </summary>
 36→        private const int ExpireTimeInSecond = 1800;
 37→
 38→        /// <summary>
 39→        /// The admin cache. There won't be too many users, so we don't need a delete mechanism.
 40→        /// </summary>
 41→        private static readonly ConcurrentDictionary<string, Tuple<bool, DateTime>> AdminCache = new ConcurrentDictionary<string, Tuple<bool, DateTime>>();
 42→
 43→        /// <summary>
 44→        /// The user cache. There won't be too many users, so we don't need a delete mechanism.
 45→        /// </summary>
 46→        private static readonly ConcurrentDictionary<string, Tuple<bool, DateTime>> UserCache = new ConcurrentDictionary<string, Tuple<bool, DateTime>>();
 47→
 48→        /// <summary>
 49→        /// The generic group membership cache for arbitrary user+group combinations.
 50→        /// </summary>
 51→        private static readonly ConcurrentDictionary<string, Tuple<bool, DateTime>> GroupMembershipCache = new ConcurrentDictionary<string, Tuple<bool, DateTime>>();
 52→
 53→        /// <summary>
 54→        /// The graph client.
 55→        /// </summary>
 56→        private readonly IMicrosoftGraphApiClient graphClient;
 57→
 58→        /// <summary>
 59→        /// Initializes a new instance of the <see cref="IdentityManager"/> class.
 60→        /// </summary>
 61→        /// <param name="graphClient">The graph client.</param>
 62→        public IdentityManager(IMicrosoftGraphApiClient graphClient)
 63→        {
 64→            this.graphClient = graphClient;
 65→        }
 66→
 67→        /// <summary>
 68→        /// Gets the graph client for external AAD group membership checks.
 69→        /// </summary>
 70→        public IMicrosoftGraphApiClient GraphClient => this.graphClient;
 71→
 72→        /// <summary>
 73→        /// Determines whether the specified user is an admin asynchronously.
 74→        /// </summary>
 75→        /// <param name="userName">The user name.</param>
 76→        /// <returns>A task that represents the asynchronous operation. The task result contains a value indicating whether the user is an admin.</returns>
 77→        public Task<bool> IsAdminAsync(string userName)
 78→        {
 79→            return this.CheckPermissionWithCacheInnerAsync(userName, AdminsSGOId, AdminCache);
 80→        }
 81→
 82→        /// <summary>
 83→        /// Determines whether the specified user is a user asynchronously.
 84→        /// </summary>
 85→        /// <param name="userName">The user name.</param>
 86→        /// <returns>A task that represents the asynchronous operation. The task result contains a value indicating whether the user is a user.</returns>
 87→        public Task<bool> IsUserAsync(string userName)
 88→        {
 89→            return this.CheckPermissionWithCacheInnerAsync(userName, UsersSGOid, UserCache);
 90→        }
 91→
 92→        /// <summary>
 93→        /// Checks if the user is a member of a specific group or owner (supports Azure AD group GUIDs).
 94→        /// </summary>
 95→        /// <param name="userName">The user name (email format).</param>
 96→        /// <param name="owner">The owner - can be a user email or Azure AD group GUID.</param>
 97→        /// <returns>True if user is the owner or member of the owner group.</returns>
 98→        public async Task<bool> IsMemberOfAsync(string userName, string owner)
 99→        {
100→            if (string.IsNullOrEmpty(owner))
101→            {
102→                return false;
103→            }
104→
105→            // Check if owner is a GUID (Azure AD group)
106→            if (Guid.TryParse(owner, out var groupId))
107→            {
108→                // Owner is a group GUID - check group membership via Graph API with caching
109→                var cacheKey = $"{userName}|{owner}";
110→                if (CheckCache(cacheKey, GroupMembershipCache, out var cachedResult))
111→                {
112→                    return cachedResult;
113→                }
114→
115→                var result = await this.graphClient.TransitiveMemberOfAsync(userName, owner);
116→                GroupMembershipCache[cacheKey] = new Tuple<bool, DateTime>(result, DateTime.UtcNow.AddSeconds(ExpireTimeInSecond));
117→                return result;
118→            }
119→            else
120→            {
121→                // Owner is a user email - direct comparison
122→                return owner.Equals(userName, StringComparison.OrdinalIgnoreCase);
123→            }
124→        }
125→
126→        /// <summary>
127→        /// Checks if the user is a member of any of the specified groups or owners (supports Azure AD group GUIDs).
128→        /// </summary>
129→        /// <param name="userName">The user name (email format).</param>
130→        /// <param name="owners">List of owners - can be user emails or Azure AD group GUIDs.</param>
131→        /// <returns>True if user is in the owners list or member of any owner group.</returns>
132→        public async Task<bool> IsMemberOfAsync(string userName, IEnumerable<string> owners)
133→        {
134→            if (owners == null)
135→            {
136→                return false;
137→            }
138→
139→            foreach (var owner in owners)
140→            {
141→                if (string.IsNullOrEmpty(owner))
142→                {
143→                    continue;
144→                }
145→
146→                if (await this.IsMemberOfAsync(userName, owner))
147→                {
148→                    return true;
149→                }
150→            }
151→
152→            return false;
153→        }
154→
155→        /// <summary>
156→        /// Checks which of the supplied group IDs the user is a member of (with caching).
157→        /// </summary>
158→        /// <param name="userName">The user name (email format).</param>
159→        /// <param name="groupIds">List of Azure AD group GUIDs.</param>
160→        /// <returns>An async stream of group IDs the user is a member of.</returns>
161→        public async IAsyncEnumerable<string> CheckMemberGroupsAsync(string userName, IEnumerable<string> groupIds)
162→        {
163→            if (string.IsNullOrEmpty(userName) || groupIds == null)
164→            {
165→                yield break;
166→            }
167→
168→            var distinctGroupIds = groupIds
169→                .Where(id => !string.IsNullOrWhiteSpace(id))
170→                .Select(id => id.Trim())
171→                .Where(id => Guid.TryParse(id, out _))
172→                .Distinct(StringComparer.OrdinalIgnoreCase)
173→                .ToList();
174→
175→            if (distinctGroupIds.Count == 0)
176→            {
177→                yield break;
178→            }
179→
180→            var pendingGroupIds = new List<string>();
181→
182→            foreach (var groupId in distinctGroupIds)
183→            {
184→                var cacheKey = $"{userName}|{groupId}";
185→                if (CheckCache(cacheKey, GroupMembershipCache, out var cachedResult))
186→                {
187→                    if (cachedResult)
188→                    {
189→                        yield return groupId;
190→                    }
191→                }
192→                else
193→                {
194→                    pendingGroupIds.Add(groupId);
195→                }
196→            }
197→
198→            if (pendingGroupIds.Count > 0)
199→            {
200→                var expiration = DateTime.UtcNow.AddSeconds(ExpireTimeInSecond);
201→                var remainingGroupIds = new HashSet<string>(pendingGroupIds, StringComparer.OrdinalIgnoreCase);
202→
203→                await foreach (var groupId in this.graphClient.CheckMemberGroupsAsync(userName, pendingGroupIds))
204→                {
205→                    if (!remainingGroupIds.Remove(groupId))
206→                    {
207→                        continue;
208→                    }
209→
210→                    GroupMembershipCache[$"{userName}|{groupId}"] = new Tuple<bool, DateTime>(true, expiration);
211→                    yield return groupId;
212→                }
213→
214→                foreach (var groupId in remainingGroupIds)
215→                {
216→                    GroupMembershipCache[$"{userName}|{groupId}"] = new Tuple<bool, DateTime>(false, expiration);
217→                }
218→            }
219→        }
220→
221→        /// <summary>
222→        /// Checks the cache for the specified user.
223→        /// </summary>
224→        /// <param name="username">The user name.</param>
225→        /// <param name="dictionary">The cache dictionary.</param>
226→        /// <param name="result">The result.</param>
227→        /// <returns>A value indicating whether the user was found in the cache and the cache entry is not expired.</returns>
228→        private static bool CheckCache(string username, ConcurrentDictionary<string, Tuple<bool, DateTime>> dictionary, out bool result)
229→        {
230→            result = false;
231→            if (dictionary.TryGetValue(username, out var value))
232→            {
233→                var entryValue = value.Item1;
234→                var entryExpirationTimestamp = value.Item2;
235→                if (DateTime.UtcNow > entryExpirationTimestamp)
236→                {
237→                    return false;
238→                }
239→
240→                result = entryValue;
241→                return true;
242→            }
243→
244→            return false;
245→        }
246→
247→        /// <summary>
248→        /// Checks the permission with cache asynchronously.
249→        /// </summary>
250→        /// <param name="userName">The user name.</param>
251→        /// <param name="groupOId">The group OID.</param>
252→        /// <param name="cache">The cache.</param>
253→        /// <returns>A task that represents the asynchronous operation. The task result contains a value indicating whether the user has the permission.</returns>
254→        private async Task<bool> CheckPermissionWithCacheInnerAsync(string userName, string groupOId, ConcurrentDictionary<string, Tuple<bool, DateTime>> cache)
255→        {
256→            if (CheckCache(userName, cache, out var result))
257→            {
258→                return result;
259→            }
260→
261→            result = await this.graphClient.TransitiveMemberOfAsync(userName, groupOId);
262→            cache[userName] = new Tuple<bool, DateTime>(result, DateTime.UtcNow.AddSeconds(ExpireTimeInSecond));
263→
264→            return result;
265→        }
266→    }
267→}
