13→        /// <summary>
14→        /// 1. Remove domain name.
15→        /// 2. remove @microsoft.com.
16→        /// 3. to lower case.
17→        /// </summary>
18→        /// <param name="alias">raw alias.</param>
19→        /// <returns>cleaned alias.</returns>
20→        public static string NormalizeAlias(string alias)
21→        {
22→            while (alias.Contains("\\"))
23→            {
24→                // remove domain
25→                alias = alias.Substring(alias.IndexOf("\\") + 1);
26→            }
27→
28→            while (alias.Contains("@"))
29→            {
30→                alias = alias.Substring(0, alias.IndexOf("@"));
31→            }
32→
33→            return alias.ToLowerInvariant();
34→        }
35→    }
