504→        {
505→            var kcsb = new KustoConnectionStringBuilder(this.kustoOptions.ClusterUri, this.kustoOptions.Database)
506→                .WithAadAzureTokenCredentialsAuthentication(this.tokenCredential!);
507→            return KustoClientFactory.CreateCslQueryProvider(kcsb);
508→        }
