528→            {
529→                var count = Math.Min(batchSize, ids.Count - i);
530→                var batch = new List<int>(count);
531→                for (int j = 0; j < count; j++)
532→                {
533→                    batch.Add(ids[i + j]);
534→                }
535→
536→                yield return batch;
537→            }
