601→        private string ResolveTokenScope(ServiceTreeKustoOptions options)
602→        {
603→            if (!string.IsNullOrWhiteSpace(options.TokenScope))
604→            {
605→                return options.TokenScope;
606→            }
607→
608→            if (Uri.TryCreate(options.ClusterUri, UriKind.Absolute, out var uri))
609→            {
610→                return $"{uri.GetLeftPart(UriPartial.Authority)}/.default";
611→            }
612→
613→            return string.Empty;
