namespace CodeXCore.ServiceTree
{
    using System;
    using System.Collections.Generic;
    using System.Linq;

    /// <summary>
    /// Hardcoded parent service group catalog.
    /// </summary>
    public static class ServiceTreeParentGroupCatalog
    {
        /// <summary>
        /// Gets the full list of parent groups.
        /// </summary>
        public static readonly IReadOnlyList<ParentServiceGroupInfo> Parents = new List<ParentServiceGroupInfo>
        {
