 1→// --------------------------------------------------------------------------------------------------------------------
 2→// <copyright file="SPICredentialFactory.cs" company="Microsoft">
 3→//   Copyright (c) Microsoft. All rights reserved.
 4→// </copyright>
 5→// --------------------------------------------------------------------------------------------------------------------
 6→
 7→namespace ISExpAuthToolkit.Credential
 8→{
 9→    using System;
10→    using System.Collections.Generic;
11→    using System.Linq;
12→    using Azure.Core;
13→    using ISExpAuthToolkit.Extensions;
14→    using ISExpAuthToolkit.Models;
15→
16→    /// <summary>
17→    /// Provides methods to create token credentials for service principals in different environments.
18→    /// </summary>
19→    public abstract class SPICredentialFactory : ICredentialFactory
20→    {
21→        /// <summary>
22→        /// Gets the original tenant.
23→        /// </summary>
24→        protected abstract AADTenant OriginalTenant { get; }
25→
26→        /// <summary>
27→        /// Gets the managed identities.
28→        /// </summary>
29→        protected abstract string[] ManagedIdentities { get; }
30→
31→        /// <summary>
32→        /// Gets the supported service principals.
33→        /// </summary>
34→        protected abstract ServicePrincipal[] SupportedSPIs { get; }
35→
36→        /// <inheritdoc/>
37→        public virtual TokenCredential CreateTokenCredential(AADTenant targetTenant = AADTenant.MSFT, ServicePrincipal servicePrincipal = null)
38→        {
39→            if (servicePrincipal == null)
40→            {
41→                var supportedForTenant = this.SupportedSPIs
42→                    .Where(spi => spi.Tenants != null && spi.Tenants.Contains(targetTenant))
43→                    .ToArray();
44→
45→                if (supportedForTenant.Length == 0)
46→                {
47→                    throw new InvalidOperationException($"No service principals configured for tenant {targetTenant}.");
48→                }
49→
50→                servicePrincipal = supportedForTenant[new Random().Next(supportedForTenant.Length)];
51→            }
52→            else if (servicePrincipal.Tenants == null || !servicePrincipal.Tenants.Contains(targetTenant))
53→            {
54→                throw new InvalidOperationException($"Service principal does not support tenant {targetTenant}.");
55→            }
56→
57→            List<Exception> miTestExceptions = new List<Exception>();
58→            foreach (var mi in this.ManagedIdentities)
59→            {
60→                try
61→                {
62→                    var tokenCred = new FederatedApplicationCredential(targetTenant.ResolveId(), mi, servicePrincipal.Id);
63→                    this.ValidateTokenCredential(tokenCred);
64→                    return tokenCred;
65→                }
66→                catch (Exception ex)
67→                {
68→                    miTestExceptions.Add(ex);
69→                }
