namespace ISExpAuthToolkit.Credential
{
    using System;
    using System.Collections.Generic;
    using System.Linq;
    using Azure.Core;
    using ISExpAuthToolkit.Extensions;
    using ISExpAuthToolkit.Models;

    /// <summary>
    /// Provides methods to create token credentials for service principals in different environments.
    /// </summary>
    public abstract class SPICredentialFactory : ICredentialFactory
    {
        /// <summary>
        /// Gets the original tenant.
        /// </summary>
        protected abstract AADTenant OriginalTenant { get; }

        /// <summary>
        /// Gets the managed identities.
        /// </summary>
        protected abstract string[] ManagedIdentities { get; }

        /// <summary>
        /// Gets the supported service principals.
        /// </summary>
        protected abstract ServicePrincipal[] SupportedSPIs { get; }

        /// <inheritdoc/>
        public virtual TokenCredential CreateTokenCredential(AADTenant targetTenant = AADTenant.MSFT, ServicePrincipal servicePrincipal = null)
        {
            if (servicePrincipal == null)
            {
                var supportedForTenant = this.SupportedSPIs
                    .Where(spi => spi.Tenants != null && spi.Tenants.Contains(targetTenant))
                    .ToArray();

                if (supportedForTenant.Length == 0)
                {
                    throw new InvalidOperationException($"No service principals configured for tenant {targetTenant}.");
                }

                servicePrincipal = supportedForTenant[new Random().Next(supportedForTenant.Length)];
            }
            else if (servicePrincipal.Tenants == null || !servicePrincipal.Tenants.Contains(targetTenant))
            {
                throw new InvalidOperationException($"Service principal does not support tenant {targetTenant}.");
            }

            List<Exception> miTestExceptions = new List<Exception>();
            foreach (var mi in this.ManagedIdentities)
            {
                try
                {
                    var tokenCred = new FederatedApplicationCredential(targetTenant.ResolveId(), mi, servicePrincipal.Id);
                    this.ValidateTokenCredential(tokenCred);
                    return tokenCred;
                }
                catch (Exception ex)
                {
                    miTestExceptions.Add(ex);
                }
            }

            throw new Exception("Failed to validate available managed identity + SPI combinations", new AggregateException(miTestExceptions));
        }

        /// <inheritdoc/>
        public TokenCredential CreateLocalTenantCredential()
        {
            return this.CreateTokenCredential(this.OriginalTenant);
        }

        /// <summary>
        /// Validates the token credential.
        /// Override this method to provide custom validation logic.
        /// </summary>
        /// <param name="tokenCredential">The token credential to validate.</param>
        public virtual void ValidateTokenCredential(TokenCredential tokenCredential)
        {
        }
    }
}

