// --------------------------------------------------------------------------------------------------------------------
// <copyright file="FederatedApplicationCredential.cs" company="Microsoft">
//   Copyright (c) Microsoft. All rights reserved.
// </copyright>
// --------------------------------------------------------------------------------------------------------------------

namespace ISExpAuthToolkit
{
    using System.Threading;
    using System.Threading.Tasks;
    using Azure.Core;
    using Azure.Identity;

    /// <summary>
    /// A <see cref="TokenCredential"/> implementation that uses a managed identity's access token
    /// as a signed client assertion when acquiring tokens for a primary client application.
    /// The primary application must have a federated credential configured to allow the managed identity to exchange tokens.
    /// </summary>
    internal sealed class FederatedApplicationCredential : TokenCredential
    {
        /// <summary>
        /// Initializes a new instance of the <see cref="FederatedApplicationCredential"/> class.
        /// </summary>
        /// <param name="tenantId">The tenant ID where the credential will be used (not necessarily the home tenant).</param>
        /// <param name="msiClientId">The client ID for the managed identity.</param>
        /// <param name="appClientId">The client ID for the application registration.</param>
        public FederatedApplicationCredential(string tenantId, string msiClientId, string appClientId)
        {
            this.ManagedIdentity = new ManagedIdentityCredential(msiClientId);
            this.ClientAssertion = new ClientAssertionCredential(tenantId, appClientId, this.ComputeAssertionAsync);
        }

        /// <summary>
        /// Initializes a new instance of the <see cref="FederatedApplicationCredential"/> class.
        /// </summary>
        /// <param name="tenantId">The tenant ID where the credential will be used (not necessarily the home tenant).</param>
        /// <param name="miCred">The managed identity credential.</param>
        /// <param name="appClientId">The client ID for the application registration.</param>
        public FederatedApplicationCredential(ManagedIdentityCredential miCred, string tenantId, string appClientId)
        {
            this.ManagedIdentity = miCred;
            this.ClientAssertion = new ClientAssertionCredential(tenantId, appClientId, this.ComputeAssertionAsync);
        }

        /// <summary>
        /// Gets the managed identity credential.
        /// </summary>
        private ManagedIdentityCredential ManagedIdentity { get; }

        /// <summary>
        /// Gets the client assertion credential.
        /// </summary>
        private ClientAssertionCredential ClientAssertion { get; }

        /// <inheritdoc/>
        public override AccessToken GetToken(TokenRequestContext requestContext, CancellationToken cancellationToken)
        {
            return this.ClientAssertion.GetToken(requestContext, cancellationToken);
        }

        /// <inheritdoc/>
        public override async ValueTask<AccessToken> GetTokenAsync(TokenRequestContext requestContext, CancellationToken cancellationToken)
        {
            return await this.ClientAssertion.GetTokenAsync(requestContext, cancellationToken);
        }

        /// <summary>
        /// Gets an exchange token from the managed identity to use as an assertion.
        /// </summary>
        /// <param name="cancellationToken">A cancellation token to cancel the operation.</param>
        /// <returns>A task that represents the asynchronous operation. The task result contains a signed assertion to authenticate with Azure AD.</returns>
        private async Task<string> ComputeAssertionAsync(CancellationToken cancellationToken)
        {
            TokenRequestContext msiContext = new TokenRequestContext(new[] { "api://AzureADTokenExchange/.default" });
            AccessToken msiToken = await this.ManagedIdentity.GetTokenAsync(msiContext, cancellationToken);
            return msiToken.Token;
        }
    }
}

