// <copyright file="DefaultCredentialFactory.cs" company="Microsoft">
// Copyright (c) Microsoft. All rights reserved.
// </copyright>

namespace ISExpAuthToolkit.Credential
{
    using System;
    using Azure.Core;
    using ISExpAuthToolkit.Environment;
    using ISExpAuthToolkit.Models;

    /// <summary>
    /// DefaultCredentialFactory, generates token credential based on detected environment.
    /// </summary>
    public class DefaultCredentialFactory : ICredentialFactory
    {
        /// <summary>
        /// The inner credential factory used to create token credentials.
        /// </summary>
        private readonly ICredentialFactory innerFactory;

        /// <summary>
        /// Initializes a new instance of the <see cref="DefaultCredentialFactory"/> class.
        /// </summary>
        public DefaultCredentialFactory()
        {
            this.innerFactory = this.DetectEnvironmentCredentialFactory();
        }

        /// <inheritdoc/>
        public TokenCredential CreateTokenCredential(AADTenant targetTenant = AADTenant.MSFT, ServicePrincipal servicePrincipal = null)
        {
            return this.innerFactory.CreateTokenCredential(targetTenant, servicePrincipal);
        }

        /// <inheritdoc/>
        public TokenCredential CreateLocalTenantCredential()
        {
            return this.innerFactory.CreateLocalTenantCredential();
        }

        /// <summary>
        /// Detects the environment and returns the appropriate credential factory.
        /// </summary>
        /// <returns>An instance of <see cref="ICredentialFactory"/> based on the detected environment.</returns>
        /// <exception cref="Exception">Thrown when the environment is unsupported.</exception>
        private ICredentialFactory DetectEnvironmentCredentialFactory()
        {
            switch (EnvironmentProperties.CurrentEnvironmentType)
            {
                case EnvironmentType.Aether:
                    return new AetherCredentialFactory();
                case EnvironmentType.Galaxy:
                    return EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Production
                        ? (ICredentialFactory)new GalaxyProdCredentialFactory()
                        : new GalaxyDevCredentialFactory();
                case EnvironmentType.EQ:
                    return new EqCredentialFactory();
                case EnvironmentType.DevBox:
                    return new DevCredentialFactory();
                case EnvironmentType.ADOPipeline:
                    return new AdoPipelineCredentialFactory();
                case EnvironmentType.CloudTest:
                    return new CloudTestCredentialFactory();
                default:
                    throw new Exception($"Unsupported environment {EnvironmentProperties.CurrentEnvironmentType}");
            }
        }
    }
}

