/// </summary>
public static class OnePortalServiceCollectionExtension
{
    /// <summary>
    /// Adds OnePortal Falcon backend services for pure backend service.
    /// </summary>
    /// <param name="services">The service collection to add the services to.</param>
    /// <param name="portalName">The name of the portal.</param>
    public static void AddOnePortalFalconBackendServices(this IServiceCollection services, string portalName)
    {
        services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
        services.AddSingleton<ICredentialFactory>(sp => sp.GetService<IEnvironmentProperties>()!.Environment == EnvironmentEnum.DevMachine ? new DefaultCredentialFactory() : new OnePortalCredentialFactory());
        services.AddSingleton<TokenCredential>(sp => sp.GetService<ICredentialFactory>()!.CreateTokenCredential());

        services.AddMdmLogging(options => options.AddDefaultCounterRules(
            $"Microsoft.Falcon.{portalName}",
            "BingIndexServeGalaxy",
            portalName));

        services.AddFalcon();
        services.AddMdsLogging();
    }

    /// <summary>
    /// Adds OnePortal Falcon services for web portal.
    /// </summary>
    /// <param name="services">The service collection to add the services to.</param>
    /// <param name="portalName">The name of the portal.</param>
    /// <param name="oneportalConfig">oneportalconfig.</param>
    public static void AddOnePortalFalconServicesSPA(this IServiceCollection services, string portalName, OnePortalConfig oneportalConfig)
    {
        services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
        services.AddSingleton<ICredentialFactory>(sp => sp.GetService<IEnvironmentProperties>()!.Environment == EnvironmentEnum.DevMachine ? new DefaultCredentialFactory() : new OnePortalCredentialFactory());
        services.AddSingleton<TokenCredential>(sp => sp.GetService<ICredentialFactory>()!.CreateTokenCredential());

        services.AddMdmLogging(options => options.AddDefaultCounterRules(
            $"Microsoft.Falcon.{portalName}",
            "BingIndexServeGalaxy",
            portalName));

        services.AddControllers();

        // Learn more about configuring Swagger/OpenAPI at https://aka.ms/aspnetcore/swashbuckle
        services.AddEndpointsApiExplorer();
        services.AddSwaggerGen();

        // Start workaround
        // We can't call services.AddFalcon() here, and we just go into the function and pick what can work to add here
        // the two comment out lines are what can't workswell
        // services.AddFalcon();

