using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.OData.Client;
using TreeODataClient.ServiceTree;
using TreeODataClient.Microsoft.Tree.CommonServiceFunctionalities.ViewModels;
using System.Collections.Generic;
using Microsoft.Tree.Client.Authentication;
using TreeODataClient.TreeWebApp.Models;

namespace TreeODataClient
{
    class Program
    {
        public static string ProdEndpoint = "https://servicetree.msftcloudes.com/cert/api";
        public static string PPEEndpoint = "https://servicetreeppe.msftcloudes.com/cert/api";
        public static string LocalEndpoint = "https://127.0.0.1/api";

        public static string CurrentEndpoint = ProdEndpoint;


        //If you don't have a thumbprint, here are the instructions to get one by following instructions at
        // https://microsoft.sharepoint.com/teams/WAG/EngSys/ServiceMgmt/ServiceTree/_layouts/15/start.aspx#/SitePages/Cert-Based%20Authentication.aspx
        public const string ThumbPrint = "fbd2f1a5a5865ddfbb09b9243221d56777ab849f";

        private static ServiceTreeContext odataClient;
        private static CertificateContext authenticationContext;

        static void Main(string[] args)
        {
            authenticationContext = new CertificateContext(new Uri(CurrentEndpoint), ThumbPrint);

            SetupOdataClient();

            var hierarchyNodes = ListAllServicesAtAllLevels();

            var metadataList = GetMetadata(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"));

            var metadata = new ServiceMetadata
            {
                AzureCloud = AzureCloudEnum.Public,
                //list of possible values can be known by querying all the metadata definitions at api/ServiceMetadataDefinitions
                MetadataDefinitionId = "Contact_DevOwner",
                //Service metadata is an open type, client code needs to expand 
                //see link for mode details http://blogs.msdn.com/b/odatateam/archive/2014/04/30/how-to-use-open-type-in-odata.aspx
                //ServiceMetadata.cs for exapnaded dev owner.
                Contact_DevOwner = "chetanra-test"
            };
            var updatedMetadata = AddMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"), metadata).GetAwaiter().GetResult();
        }

        ///<summary>
        ///Get Metadata for a service, microservice or component
        ///</summary>
        public static IEnumerable<ServiceMetadata> GetMetadata(Guid serviceHierarchyId)
        {
            var metadata = odataClient.ServiceHierarchy.ByKey(serviceHierarchyId).GetMetadata();

            foreach (var item in metadata)
            {
                Console.WriteLine(item.MetadataDefinitionId);
            }

            return metadata.ToList();
        }

        /// <summary>
        /// Sets Metadata for a service, microservice or component
        /// You need to be an admin of the service that you are setting the metadata on
        /// Or admin of the service that owns the metadata definition
        /// </summary>
        public static async Task<ServiceMetadata> AddMetadataAsync(Guid serviceHierarchyId, ServiceMetadata metadata)
        {
            var updatedmetadata = await odataClient.ServiceHierarchy.ByKey(serviceHierarchyId).AddMetadata(metadata).GetValueAsync();
            return updatedmetadata;
        }

        /// <summary>
        /// This demons retrieving a flat list of services, microservices and components from the service tree.
        /// </summary>
        public static IEnumerable<ServiceHierarchy> ListAllServicesAtAllLevels()
        {
            foreach (var node in odataClient.ServiceHierarchy)
            {
                Console.WriteLine("{0} --- {1} --- {2}", node.Name, node.NodeType, node.Id);
            }

            return odataClient.ServiceHierarchy.Where(node => node.NodeType == "Service").ToList();
        }

        private static void SetupOdataClient()
        {
            odataClient = new ServiceTreeContext(authenticationContext.ApiUri);
            odataClient.SendingRequest2 += authenticationContext.OnSendingRequestAddAuthenticationHeaders;
        }
    }
}

