            GetMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea")).GetAwaiter().GetResult();

            //Properties here are listed in ServiceMetadata entity in /api/$metadata
            var metadata = new
            {
                //list of possible values can be seen in api/$metadata for AzureCloudEnum
                AzureCloud = "Public",
                //list of possible values can be known by querying all the metadata definitions at api/ServiceMetadataDefinitions
                MetadataDefinitionId = "Contact_DevOwner",
                Contact_DevOwner = "chetanra-test"
            };
            AddMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"), metadata).GetAwaiter().GetResult();
        }

        /// <summary>
        /// This demons retrieving a flat list of services, microservices and components from the service tree.
        /// </summary>
        public static async Task ListAllServicesAtAllLevelsAsync()
        {
            //url is case sensitive
            var url = string.Format("{0}/ServiceHierarchy", ProdEndpoint);

            var client = authenticationContext.GetHttpClient();

            var response = await client.GetStringAsync(url);
            dynamic responseMessage = JObject.Parse(response);

            dynamic serviceHierarchy = responseMessage["value"];

            foreach (var item in serviceHierarchy)
            {
                //Get to know all the properties exposed by ServiceHierarchy by going to /api/$metadata and searchign for string "EntityType Name="ServiceHierarchy""
                Console.WriteLine("{0} --- {1} --- {2}", item["Name"], item["NodeType"], item["Id"]);
            }
        }


        /// <summary>
        /// Get Metadata for a service, microservice or component
        /// </summary>
        public static async Task<object> GetMetadataAsync(Guid serviceHierarchyId)
        {
            //url is case sensitive
            var url = string.Format("{0}/ServiceHierarchy({1})/ServiceTree.GetMetadata", ProdEndpoint, serviceHierarchyId);

            var client = authenticationContext.GetHttpClient();

            var response = await client.GetStringAsync(url);

            dynamic responseMessage = JObject.Parse(response);

            dynamic serviceMetadataList = responseMessage["value"];

            foreach (var item in serviceMetadataList)
            {
                //Get to know all the properties exposed by ServiceMetadata by going to /api/$metadata and searchign for string "EntityType Name="ServiceMetadata""
                Console.WriteLine("{0} --- {1}", item["Id"], item["MetadataDefinitionId"]);
            }

            return serviceMetadataList;
        }

        /// <summary>
        /// Sets Metadata for a service, microservice or component
        /// You need to be an admin of the service that you are setting the metadata on
        /// Or admin of the service that owns the metadata definition
        /// </summary>
        public static async Task<object> AddMetadataAsync(Guid serviceHierarchyId, object metadata)
        {
            //url is case sensitive
            var url = string.Format("{0}/ServiceHierarchy({1})/ServiceTree.AddMetadata", ProdEndpoint, serviceHierarchyId);

            var client = authenticationContext.GetHttpClient();

            var response = await client.PostAsync(url, new StringContent(JsonConvert.SerializeObject(new { ServiceMetadata = metadata }), Encoding.UTF8, "application/json") as HttpContent);

            var responseString = await response.Content.ReadAsStringAsync();

            dynamic jsonResponse = JObject.Parse(responseString);

            //Get to know all the properties exposed by ServiceMetadata by going to /api/$metadata and searchign for string "EntityType Name="ServiceMetadata""
            Console.WriteLine("{0} --- {1}", jsonResponse["Id"], jsonResponse["Contact_DevOwner"]);

            return jsonResponse;
        }
    }
}

