namespace CodeXCore.ServiceTree
{
    using System;
    using System.Net.Http;
    using System.Net.Http.Headers;
    using System.Security;
    using System.Security.Cryptography;
    using System.Security.Cryptography.X509Certificates;
    using System.Text.Json;
    using System.Threading;
    using System.Threading.Tasks;
    using global::Azure.Core;
    using global::Azure.Identity;
    using Microsoft.Extensions.Logging;

#pragma warning disable CA1303 // Log messages are not localized.

    /// <summary>
    /// Lightweight Service Tree client that retrieves node details via REST.
    /// </summary>
    public sealed class ServiceTreeClient : IServiceTreeClient, IDisposable
    {
        private readonly HttpClient httpClient;
        private readonly Uri baseUri;
        private readonly ILogger<ServiceTreeClient> logger;
        private readonly bool isConfigured;
        private readonly ServiceTreeAuthenticationMode authenticationMode;
        private readonly TokenCredential? tokenCredential;
        private readonly string? tokenScope;

        /// <summary>
        /// Initializes a new instance of the <see cref="ServiceTreeClient"/> class.
        /// </summary>
        /// <param name="options">Client options.</param>
        /// <param name="logger">Logger instance.</param>
        public ServiceTreeClient(ServiceTreeClientOptions options, ILogger<ServiceTreeClient> logger)
        {
            if (options == null)
            {
                throw new ArgumentNullException(nameof(options));
            }

            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
            this.baseUri = new Uri(this.AppendTrailingSlash(options.Endpoint));
            this.authenticationMode = options.AuthenticationMode;

#pragma warning disable CA2000 // HttpClient owns handler when disposeHandler is true.
            HttpClientHandler handler = new HttpClientHandler();
#pragma warning restore CA2000
            try
            {
                if (this.authenticationMode == ServiceTreeAuthenticationMode.Aad)
                {
                    this.tokenCredential = this.TryCreateAadCredential(options, out var scope);
                    if (this.tokenCredential != null && !string.IsNullOrWhiteSpace(scope))
                    {
                        this.tokenScope = scope;
                        this.isConfigured = true;
                    }
                    else
                    {
                        this.logger.LogWarning("ServiceTreeClient: AAD authentication is enabled, but credentials are not configured.");
                        this.isConfigured = false;
                    }
                }
                else if (this.authenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
                {
                    this.tokenCredential = this.CreateDefaultAzureCredential(options, out var scope);
                    if (this.tokenCredential != null && !string.IsNullOrWhiteSpace(scope))
                    {
                        this.tokenScope = scope;
                        this.isConfigured = true;
                    }
                    else
                    {
                        this.logger.LogWarning("ServiceTreeClient: DefaultAzureCredential auth is enabled, but no token scope is configured.");
                        this.isConfigured = false;
                    }
                }
                else
                {
                    var cert = this.TryLoadCertificate(options);
                    if (cert != null)
                    {
                        handler.ClientCertificates.Add(cert);
                        this.isConfigured = true;
                    }
                    else
                    {
                        this.logger.LogWarning("ServiceTreeClient: no client certificate found. Requests may fail without cert-based auth.");
                        this.isConfigured = false;
                    }
                }

                this.httpClient = new HttpClient(handler, disposeHandler: true);
                handler = null;
                this.httpClient.Timeout = TimeSpan.FromSeconds(30);
            }
            finally
            {
                handler?.Dispose();
            }
        }

        /// <inheritdoc/>
        public async Task<ServiceTreeNode?> GetServiceHierarchyAsync(Guid id, CancellationToken cancellationToken)
        {
            if (!this.isConfigured)
            {
                return null;
            }

            var requestUri = new Uri(this.baseUri, $"ServiceHierarchy({id})?$select=Id,Name,OrganizationPath,Path,NodeType,ParentNodeType");
            try
            {
                using var request = new HttpRequestMessage(HttpMethod.Get, requestUri);
                if (this.authenticationMode == ServiceTreeAuthenticationMode.Aad
                    || this.authenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
                {
                    var token = await this.GetAccessTokenAsync(cancellationToken).ConfigureAwait(false);
                    if (string.IsNullOrWhiteSpace(token))
                    {
                        return null;
                    }

                    request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
                }

                using var response = await this.httpClient.SendAsync(request, cancellationToken).ConfigureAwait(false);
                if (!response.IsSuccessStatusCode)
                {
                    var body = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
                    this.logger.LogWarning("ServiceTreeClient: request failed ({Status}) for {Id}. Body: {Body}", response.StatusCode, id, body);
                    return null;
                }

                var content = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
                if (string.IsNullOrWhiteSpace(content))
                {
                    return null;
                }

                using var doc = JsonDocument.Parse(content);
                var root = doc.RootElement;

                if (root.ValueKind != JsonValueKind.Object)
                {
                    return null;
                }

                return new ServiceTreeNode
                {
                    InternalId = 0,
                    Id = this.TryGetString(root, "Id"),
                    Level = string.Empty,
                    ParentInternalId = 0,
                    Name = this.TryGetString(root, "Name"),
                    OrganizationPath = this.TryGetString(root, "OrganizationPath"),
                    Path = this.TryGetString(root, "Path"),
                    NodeType = this.TryGetString(root, "NodeType"),
                    ParentNodeType = this.TryGetString(root, "ParentNodeType"),
                };
            }
            catch (OperationCanceledException)
            {
                throw;
            }
            catch (CredentialUnavailableException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: AAD credentials unavailable for {Id}.", id);
                return null;
            }
            catch (AuthenticationFailedException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: AAD authentication failed for {Id}.", id);
                return null;
            }
            catch (HttpRequestException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: request failed for {Id}.", id);
                return null;
            }
            catch (JsonException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: invalid response for {Id}.", id);
                return null;
            }
            catch (InvalidOperationException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: failed to process response for {Id}.", id);
                return null;
            }
            catch (FormatException ex)
            {
                this.logger.LogWarning(ex, "ServiceTreeClient: malformed response for {Id}.", id);
                return null;
            }
        }

        /// <summary>
        /// Disposes managed resources.
        /// </summary>
        public void Dispose()
        {
            this.httpClient.Dispose();
        }

        private string AppendTrailingSlash(string endpoint)
        {
            if (string.IsNullOrWhiteSpace(endpoint))
            {
                return string.Empty;
            }

            return endpoint.EndsWith("/", StringComparison.Ordinal) ? endpoint : $"{endpoint}/";
        }

        private async Task<string> GetAccessTokenAsync(CancellationToken cancellationToken)
        {
            if (this.tokenCredential == null || string.IsNullOrWhiteSpace(this.tokenScope))
            {
                return string.Empty;
            }

            var tokenRequest = new TokenRequestContext(new[] { this.tokenScope });
            var token = await this.tokenCredential.GetTokenAsync(tokenRequest, cancellationToken).ConfigureAwait(false);
            return token.Token;
        }

        private TokenCredential? TryCreateAadCredential(ServiceTreeClientOptions options, out string scope)
        {
            scope = this.ResolveAadScope(options);
            if (string.IsNullOrWhiteSpace(scope))
            {
                this.logger.LogWarning("ServiceTreeClient: AAD scope is not configured.");
                return null;
            }

            if (!string.IsNullOrWhiteSpace(options.AadClientSecret))
            {
